import { shallowEqual } from ':helpers/shallowEqual';
import { useMemo } from 'react';

import type { Option } from '../../Select.types'; // Импортируйте нужные типы

interface AddArrayIndex<T> {
	options?: T[];
	values?: T[];
}

// TODO надо придумать адекватное название
export const useAddArrayIndex = <T>({ options = [], values = [] }: AddArrayIndex<T>) => {
	// добавляем опциям айдишники, пользователю они ни к чему
	const privateOptions = useMemo<Array<Option<T>>>(
		() =>
			options?.map((option, index) => ({
				id: index,
				value: option,
				disabled: (option as any)?.disabled,
			})),
		[options],
	);

	// добавляем выбранным значениям айдишники, пользователю они ни к чему
	const privateValues = useMemo<Array<Option<T>>>(
		() =>
			values.map(value => {
				const id = privateOptions?.find(opt => shallowEqual(opt.value, value))?.id;
				return {
					id,
					value,
				};
			}),
		[values, privateOptions],
	);

	return [privateOptions, privateValues];
};
